  1→//! Discovered model types and merge helpers for model list composition.
  2→
  3→use std::collections::{HashMap, HashSet};
  4→
  5→use crate::model_capabilities::ModelCapabilities;
  6→
  7→/// A model discovered from a provider API (e.g. `/v1/models`).
  8→///
  9→/// Replaces bare `(String, String)` tuples so that optional metadata
 10→/// such as `created_at` can travel alongside the id/display_name pair.
 11→#[derive(Debug, Clone)]
 12→pub struct DiscoveredModel {
 13→    pub id: String,
 14→    pub display_name: String,
 15→    /// Unix timestamp from the API (e.g. OpenAI `created` field).
 16→    /// Used to sort models newest-first. `None` for static catalog entries.
 17→    pub created_at: Option<i64>,
 18→    /// Flagged by the provider as a recommended/flagship model.
 19→    /// Used to surface the most relevant models in the UI.
 20→    pub recommended: bool,
 21→    pub capabilities: Option<ModelCapabilities>,
 22→}
 23→
 24→impl DiscoveredModel {
 25→    pub fn new(id: impl Into<String>, display_name: impl Into<String>) -> Self {
 26→        Self {
 27→            id: id.into(),
 28→            display_name: display_name.into(),
 29→            created_at: None,
 30→            recommended: false,
 31→            capabilities: None,
 32→        }
 33→    }
 34→
 35→    pub fn with_created_at(mut self, created_at: Option<i64>) -> Self {
 36→        self.created_at = created_at;
 37→        self
 38→    }
 39→
 40→    pub fn with_recommended(mut self, recommended: bool) -> Self {
 41→        self.recommended = recommended;
 42→        self
 43→    }
 44→
 45→    pub fn with_capabilities(mut self, capabilities: ModelCapabilities) -> Self {
 46→        self.capabilities = Some(capabilities);
 47→        self
 48→    }
 49→}
 50→
 51→/// Convert a static model catalog into `DiscoveredModel` entries, marking
 52→/// the first `recommended_count` as recommended.
 53→pub fn catalog_to_discovered(
 54→    catalog: &[(&str, &str)],
 55→    recommended_count: usize,
 56→) -> Vec<DiscoveredModel> {
 57→    catalog
 58→        .iter()
 59→        .enumerate()
 60→        .map(|(i, (id, name))| {
 61→            DiscoveredModel::new(*id, *name).with_recommended(i < recommended_count)
 62→        })
 63→        .collect()
 64→}
 65→
 66→pub(crate) fn merge_preferred_and_discovered_models(
 67→    preferred: Vec<String>,
 68→    discovered: Vec<DiscoveredModel>,
 69→) -> Vec<DiscoveredModel> {
 70→    let discovered_by_id: HashMap<String, &DiscoveredModel> =
 71→        discovered.iter().map(|m| (m.id.clone(), m)).collect();
 72→    let mut merged = Vec::new();
 73→    let mut seen = HashSet::new();
 74→
 75→    for model_id in preferred {
 76→        if !seen.insert(model_id.clone()) {
 77→            continue;
 78→        }
 79→        let model = if let Some(d) = discovered_by_id.get(&model_id) {
 80→            DiscoveredModel {
 81→                id: model_id,
 82→                display_name: d.display_name.clone(),
 83→                created_at: d.created_at,
 84→                recommended: d.recommended,
 85→                capabilities: d.capabilities,
 86→            }
 87→        } else {
 88→            DiscoveredModel::new(model_id.clone(), model_id)
 89→        };
 90→        merged.push(model);
 91→    }
 92→
 93→    for model in discovered {
 94→        if !seen.insert(model.id.clone()) {
 95→            continue;
 96→        }
 97→        merged.push(model);
 98→    }
 99→
100→    merged
101→}
102→
103→pub(crate) fn merge_discovered_with_fallback_catalog(
104→    discovered: Vec<DiscoveredModel>,
105→    fallback: Vec<DiscoveredModel>,
106→) -> Vec<DiscoveredModel> {
107→    if discovered.is_empty() {
108→        return fallback;
109→    }
110→
111→    let fallback_by_id: HashMap<String, DiscoveredModel> =
112→        fallback.into_iter().map(|m| (m.id.clone(), m)).collect();
113→    discovered
114→        .into_iter()
115→        .map(|m| {
116→            let display_name = if m.display_name.trim().is_empty() {
117→                fallback_by_id
118→                    .get(&m.id)
119→                    .map(|fb| fb.display_name.clone())
120→                    .unwrap_or_else(|| m.id.clone())
121→            } else {
122→                m.display_name
123→            };
124→            DiscoveredModel {
125→                id: m.id,
126→                display_name,
127→                created_at: m.created_at,
128→                recommended: m.recommended,
129→                capabilities: m.capabilities,
130→            }
131→        })
132→        .collect()
133→}
134→
135→#[cfg(test)]
136→#[allow(clippy::unwrap_used, clippy::expect_used)]
137→mod tests {
138→    use super::*;
139→
140→    #[test]
141→    fn merge_discovered_with_fallback_keeps_discovered_when_non_empty() {
142→        let merged = merge_discovered_with_fallback_catalog(
143→            vec![
144→                DiscoveredModel::new("live-a", "Live A"),
145→                DiscoveredModel::new("live-b", "Live B"),
146→            ],
147→            vec![
148→                DiscoveredModel::new("live-a", "Fallback A"),
149→                DiscoveredModel::new("fallback-only", "Fallback Only"),
150→            ],
151→        );
152→
153→        let ids: Vec<&str> = merged.iter().map(|m| m.id.as_str()).collect();
154→        assert_eq!(ids, vec!["live-a", "live-b"]);
155→    }
156→
157→    #[test]
158→    fn merge_discovered_with_fallback_uses_fallback_when_discovered_empty() {
159→        let merged = merge_discovered_with_fallback_catalog(Vec::new(), vec![
160→            DiscoveredModel::new("fallback-a", "Fallback A"),
161→            DiscoveredModel::new("fallback-b", "Fallback B"),
162→        ]);
163→
164→        let ids: Vec<&str> = merged.iter().map(|m| m.id.as_str()).collect();
165→        assert_eq!(ids, vec!["fallback-a", "fallback-b"]);
166→    }
167→}
