259→/// Capabilities that a model is known to support.
260→///
261→/// Populated at registration time from the pattern-matching heuristics.
262→/// Carried on `ModelInfo` so downstream code can check capabilities
263→/// without a provider instance or re-running the heuristic.
264→#[derive(Debug, Clone, Copy, Default, PartialEq, Eq, serde::Serialize)]
265→pub struct ModelCapabilities {
266→    /// Supports OpenAI-style function/tool calling.
267→    pub tools: bool,
268→    /// Supports image/vision inputs.
269→    pub vision: bool,
270→    /// Supports extended thinking / reasoning effort.
271→    pub reasoning: bool,
272→}
273→
274→impl ModelCapabilities {
275→    /// Infer capabilities from the model ID using the pattern-matching heuristics.
276→    #[must_use]
277→    pub fn infer(model_id: &str) -> Self {
278→        Self {
279→            tools: supports_tools_for_model(model_id),
280→            vision: supports_vision_for_model(model_id),
281→            reasoning: supports_reasoning_for_model(model_id),
282→        }
283→    }
284→}
