286→/// Info about an available model.
287→#[derive(Debug, Clone, serde::Serialize)]
288→pub struct ModelInfo {
289→    pub id: String,
290→    pub provider: String,
291→    pub display_name: String,
292→    /// Unix timestamp from the provider API (e.g. OpenAI `created` field).
293→    /// `None` for static catalog entries.
294→    pub created_at: Option<i64>,
295→    /// Flagged by the provider as a recommended/flagship model.
296→    pub recommended: bool,
297→    /// Model capabilities, resolved at registration time.
298→    pub capabilities: ModelCapabilities,
299→}
