343→
344→    #[test]
345→    fn qwen3_context_window() {
346→        assert_eq!(context_window_for_model("qwen3.6-plus"), 128_000);
347→        assert_eq!(context_window_for_model("qwen3.5-plus"), 128_000);
348→        assert_eq!(context_window_for_model("qwen3-max-2026-01-23"), 128_000);
