353→    #[test]
354→    fn supports_vision_for_known_models() {
355→        // Claude models support vision
356→        assert!(supports_vision_for_model("claude-sonnet-4-20250514"));
357→        assert!(supports_vision_for_model("claude-opus-4-5-20251101"));
358→        assert!(supports_vision_for_model("claude-3-haiku-20240307"));
359→
360→        // GPT-4o variants support vision
361→        assert!(supports_vision_for_model("gpt-4o"));
362→        assert!(supports_vision_for_model("gpt-4o-mini"));
363→        assert!(supports_vision_for_model("openrouter::openai/gpt-4o"));
364→
365→        // GPT-4 turbo and vision variants support vision
366→        assert!(supports_vision_for_model("gpt-4-turbo"));
367→        assert!(supports_vision_for_model("gpt-4-vision-preview"));
368→
369→        // GPT-5 supports vision
370→        assert!(supports_vision_for_model("gpt-5.2-codex"));
371→
372→        // o3/o4 series supports vision
373→        assert!(supports_vision_for_model("o3"));
374→        assert!(supports_vision_for_model("o3-mini"));
375→        assert!(supports_vision_for_model("o4-mini"));
376→
377→        // Gemini supports vision
378→        assert!(supports_vision_for_model("gemini-2.0-flash"));
379→        assert!(supports_vision_for_model(
380→            "custom-openrouter::google/gemini-2.0-flash"
381→        ));
382→
383→        // Z.AI vision models
384→        assert!(supports_vision_for_model("glm-4.6v"));
385→        assert!(supports_vision_for_model("glm-4.6v-flash"));
386→        assert!(supports_vision_for_model("glm-4.5v"));
387→
388→        // Mistral vision-capable models
389→        assert!(supports_vision_for_model("mistral-large-latest"));
390→        assert!(supports_vision_for_model("mistral-medium-2505"));
391→        assert!(supports_vision_for_model("mistral-small-latest"));
392→        assert!(supports_vision_for_model("pixtral-large-latest"));
393→        assert!(supports_vision_for_model("pixtral-12b-2409"));
394→
395→        // Qwen vision models
396→        assert!(supports_vision_for_model("qwen-vl-max"));
397→        assert!(supports_vision_for_model("qwen2.5-vl-72b"));
398→        assert!(supports_vision_for_model("qwen3-vl-8b"));
399→
400→        // Unknown models default to vision support (better to try and fail
401→        // with an API error than to silently strip images)
402→        assert!(supports_vision_for_model("some-unknown-model"));
