  1→//! Live integration tests for the OpenRouter provider.
  2→//!
  3→//! Requires `OPENROUTER_API_KEY`. Run with:
  4→//!   cargo test --test openrouter_integration -- --ignored
  5→//!
  6→//! OpenRouter is a model router — it proxies requests to upstream providers.
  7→//! We test with a cheap, reliable model to validate the integration path.
  8→
  9→#![allow(clippy::unwrap_used, clippy::expect_used)]
 10→
 11→use {
 12→    futures::StreamExt,
 13→    moltis_agents::model::{ChatMessage, LlmProvider, StreamEvent, ToolCall},
 14→    moltis_providers::openai::OpenAiProvider,
 15→    secrecy::{ExposeSecret, Secret},
 16→};
 17→
 18→const BASE_URL: &str = "https://openrouter.ai/api/v1";
 19→/// Use a cheap model for testing. OpenRouter has no static catalog — models
 20→/// are discovered via API.
 21→const TEST_MODEL: &str = "openai/gpt-4o-mini";
 22→
 23→fn api_key() -> Secret<String> {
 24→    Secret::new(
 25→        std::env::var("OPENROUTER_API_KEY")
 26→            .expect("OPENROUTER_API_KEY must be set for integration tests"),
 27→    )
 28→}
 29→
 30→fn make_provider(model: &str) -> OpenAiProvider {
 31→    OpenAiProvider::new_with_name(
 32→        api_key(),
 33→        model.to_string(),
 34→        BASE_URL.to_string(),
 35→        "openrouter".to_string(),
 36→    )
 37→}
 38→
 39→fn weather_tool() -> serde_json::Value {
 40→    serde_json::json!({
 41→        "name": "get_weather",
 42→        "description": "Get current weather for a location. You MUST call this tool when asked about weather.",
 43→        "parameters": {
 44→            "type": "object",
 45→            "properties": {
 46→                "location": { "type": "string", "description": "City name" }
 47→            },
 48→            "required": ["location"]
 49→        }
 50→    })
 51→}
 52→
 53→// ── System prompt ────────────────────────────────────────────────────────────
 54→
 55→#[tokio::test]
 56→#[ignore]
 57→async fn system_prompt_is_received_non_streaming() {
 58→    let p = make_provider(TEST_MODEL);
 59→    let keyword = "PERSIMMON";
 60→    let messages = vec![
 61→        ChatMessage::system(format!(
 62→            "You MUST include the exact word \"{keyword}\" in every response, no matter what."
 63→        )),
 64→        ChatMessage::user("What is 2+2?"),
 65→    ];
 66→    let response = p.complete(&messages, &[]).await.expect("should succeed");
 67→    let text = response.text.expect("must have text");
 68→    assert!(
 69→        text.to_lowercase().contains(&keyword.to_lowercase()),
 70→        "system prompt not received: {text:?}"
 71→    );
 72→}
 73→
 74→#[tokio::test]
 75→#[ignore]
 76→async fn system_prompt_is_received_streaming() {
 77→    let p = make_provider(TEST_MODEL);
 78→    let keyword = "GUAVA";
 79→    let messages = vec![
 80→        ChatMessage::system(format!(
 81→            "You MUST include the exact word \"{keyword}\" in every response, no matter what."
 82→        )),
 83→        ChatMessage::user("What is 3+3?"),
 84→    ];
 85→    let mut stream = p.stream_with_tools(messages, vec![]);
 86→    let mut full_text = String::new();
 87→    let mut saw_done = false;
 88→    while let Some(event) = stream.next().await {
 89→        match event {
 90→            StreamEvent::Delta(chunk) => full_text.push_str(&chunk),
 91→            StreamEvent::Done(_) => {
 92→                saw_done = true;
 93→                break;
 94→            },
 95→            StreamEvent::Error(err) => panic!("stream error: {err}"),
 96→            _ => {},
 97→        }
 98→    }
 99→    assert!(saw_done, "stream must emit Done");
100→    assert!(
101→        full_text.to_lowercase().contains(&keyword.to_lowercase()),
102→        "system prompt not received: {full_text:?}"
103→    );
104→}
