108→#[tokio::test]
109→#[ignore]
110→async fn tool_call_round_trip_non_streaming() {
111→    let p = make_provider(TEST_MODEL);
112→    let response = p
113→        .complete(
114→            &[ChatMessage::user(
115→                "What's the weather in Tokyo? Use the get_weather tool.",
116→            )],
117→            &[weather_tool()],
118→        )
119→        .await
120→        .expect("should succeed");
121→    assert!(
122→        !response.tool_calls.is_empty(),
123→        "should call tool, got text: {:?}",
124→        response.text
125→    );
126→    assert_eq!(response.tool_calls[0].name, "get_weather");
127→}
