129→#[tokio::test]
130→#[ignore]
131→async fn tool_call_round_trip_streaming() {
132→    let p = make_provider(TEST_MODEL);
133→    let mut stream = p.stream_with_tools(
134→        vec![ChatMessage::user(
135→            "What's the weather in Paris? Use the get_weather tool.",
136→        )],
137→        vec![weather_tool()],
138→    );
139→    let mut saw_tool = false;
140→    let mut saw_done = false;
141→    let mut tool_name = String::new();
142→    while let Some(event) = stream.next().await {
143→        match event {
144→            StreamEvent::ToolCallStart { name, .. } => {
145→                saw_tool = true;
146→                tool_name = name;
147→            },
148→            StreamEvent::Done(_) => {
149→                saw_done = true;
150→                break;
151→            },
152→            StreamEvent::Error(err) => panic!("stream error: {err}"),
153→            _ => {},
154→        }
155→    }
156→    assert!(saw_done, "must emit Done");
157→    assert!(saw_tool, "should include tool call");
158→    assert_eq!(tool_name, "get_weather");
159→}
