161→#[tokio::test]
162→#[ignore]
163→async fn multi_turn_tool_use() {
164→    let p = make_provider(TEST_MODEL);
165→    let tools = vec![weather_tool()];
166→    let r = p
167→        .complete(
168→            &[ChatMessage::user("Weather in London? Use get_weather.")],
169→            &tools,
170→        )
171→        .await
172→        .expect("first turn");
173→    assert!(!r.tool_calls.is_empty(), "should call tool");
174→    let tc = &r.tool_calls[0];
175→    let r2 = p
176→        .complete(
177→            &[
178→                ChatMessage::user("Weather in London? Use get_weather."),
179→                ChatMessage::assistant_with_tools(r.text.clone(), vec![ToolCall {
180→                    id: tc.id.clone(),
181→                    name: tc.name.clone(),
182→                    arguments: tc.arguments.clone(),
183→                }]),
184→                ChatMessage::tool(&tc.id, r#"{"temperature": 15, "condition": "cloudy"}"#),
185→            ],
186→            &tools,
187→        )
188→        .await
