 64→    default_provider: Arc<dyn LlmProvider>,
 65→    tool_registry: Arc<ToolRegistry>,
 66→    agents_config: Option<Arc<tokio::sync::RwLock<AgentsConfig>>>,
 67→    on_event: Option<OnSpawnEvent>,
 68→    session_deps: Option<SessionDeps>,
 69→}
