 71→impl SpawnAgentTool {
 72→    pub fn new(
 73→        provider_registry: Arc<tokio::sync::RwLock<ProviderRegistry>>,
 74→        default_provider: Arc<dyn LlmProvider>,
 75→        tool_registry: Arc<ToolRegistry>,
 76→    ) -> Self {
 77→        Self {
 78→            provider_registry,
 79→            default_provider,
 80→            tool_registry,
 81→            agents_config: None,
 82→            on_event: None,
 83→            session_deps: None,
 84→        }
 85→    }
