 97→    ) -> Self {
 98→        self.agents_config = Some(agents_config);
 99→        self
100→    }
101→
102→    /// Provide session dependencies so sub-agents can get policy-aware session tools.
103→    pub fn with_session_deps(mut self, deps: SessionDeps) -> Self {
104→        self.session_deps = Some(deps);
105→        self
106→    }
107→
108→    fn emit(&self, event: RunnerEvent) {
109→        if let Some(ref cb) = self.on_event {
110→            cb(event);
111→        }
112→    }
113→
114→    fn build_sub_tools(
115→        &self,
116→        allow_tools: &[String],
117→        deny_tools: &[String],
118→        delegate_only: bool,
119→    ) -> ToolRegistry {
120→        let mut sub_tools = if delegate_only {
121→            let allowed: HashSet<&str> = DELEGATE_TOOLS.iter().copied().collect();
122→            self.tool_registry
123→                .clone_allowed_by(|name| allowed.contains(name))
124→        } else if !allow_tools.is_empty() {
125→            let allowed: HashSet<&str> = allow_tools.iter().map(String::as_str).collect();
126→            self.tool_registry
127→                .clone_allowed_by(|name| name != "spawn_agent" && allowed.contains(name))
128→        } else {
129→            // Default behavior preserves old semantics.
130→            self.tool_registry.clone_without(&["spawn_agent"])
131→        };
132→
133→        if !deny_tools.is_empty() {
134→            let deny: HashSet<&str> = deny_tools.iter().map(String::as_str).collect();
135→            sub_tools = sub_tools.clone_allowed_by(|name| !deny.contains(name));
136→        }
137→
138→        sub_tools
139→    }
