141→    /// Apply reasoning_effort from the agent preset to the provider, if set.
142→    ///
143→    /// Returns the original provider if reasoning_effort is not configured or
144→    /// the provider doesn't support it. Warns when the preset overrides a
145→    /// reasoning effort already set via the model ID suffix.
146→    fn maybe_apply_reasoning_effort(
147→        provider: Arc<dyn LlmProvider>,
148→        preset: Option<&AgentPreset>,
149→    ) -> Arc<dyn LlmProvider> {
150→        let Some(effort) = preset.and_then(|p| p.reasoning_effort) else {
151→            return provider;
152→        };
153→        // Warn if the provider already has a (different) reasoning effort from
154→        // the model ID suffix — the preset value will take precedence.
155→        if let Some(existing) = provider.reasoning_effort()
156→            && existing != effort
157→        {
158→            tracing::warn!(
159→                model = %provider.id(),
160→                existing = ?existing,
161→                preset = ?effort,
162→                "preset reasoning_effort overrides model-ID suffix; using preset value"
163→            );
164→        }
165→        let cloned = Arc::clone(&provider);
166→        let new_provider = cloned.with_reasoning_effort(effort);
167→        if new_provider.is_none() {
168→            info!(
169→                model = %provider.id(),
170→                ?effort,
171→                "provider does not support reasoning effort; ignoring preset setting"
172→            );
173→        }
174→        new_provider.unwrap_or(provider)
175→    }
176→
177→    async fn resolve_preset(
178→        &self,
179→        params: &serde_json::Value,
180→    ) -> crate::Result<(Option<String>, Option<AgentPreset>)> {
181→        let explicit_name = str_param(params, "preset").map(String::from);
182→
183→        let Some(ref agents_config) = self.agents_config else {
184→            if explicit_name.is_some() {
185→                return Err(Error::message(
186→                    "spawn preset requested but agents presets are not configured",
187→                ));
188→            }
189→            return Ok((None, None));
190→        };
191→
192→        let agents = agents_config.read().await;
193→        let preset_name = explicit_name.or_else(|| agents.default_preset.clone());
194→        let Some(preset_name) = preset_name else {
195→            return Ok((None, None));
196→        };
197→        let preset = agents.get_preset(&preset_name).cloned().ok_or_else(|| {
198→            Error::message(format!(
199→                "spawn preset '{preset_name}' not found in config.agents.presets"
200→            ))

