139→fn formatted_model_name(model_id: &str) -> String {
140→    let raw = model_id.strip_prefix("claude-").unwrap_or(model_id);
141→    let mut pieces = Vec::new();
142→    let chunks: Vec<&str> = raw.split('-').filter(|chunk| !chunk.is_empty()).collect();
143→    let mut index = 0usize;
144→    while index < chunks.len() {
145→        let chunk = chunks[index];
146→        let piece = if chunk.chars().all(|ch| ch.is_ascii_digit()) && chunk.len() == 1 {
147→            if let Some(next) = chunks.get(index + 1)
148→                && next.chars().all(|ch| ch.is_ascii_digit())
149→                && next.len() == 1
150→            {
151→                index += 1;
152→                format!("{chunk}.{next}")
153→            } else {
154→                chunk.to_string()
155→            }
156→        } else if chunk.chars().all(|ch| ch.is_ascii_digit()) && chunk.len() == 8 {
157→            let year = &chunk[0..4];
158→            let month = &chunk[4..6];
159→            let day = &chunk[6..8];
160→            format!("{year}-{month}-{day}")
161→        } else {
162→            let mut chars = chunk.chars();
163→            match chars.next() {
164→                Some(first) => {
165→                    let mut out = String::new();
166→                    out.push(first.to_ascii_uppercase());
167→                    out.push_str(chars.as_str());
168→                    out
169→                },
170→                None => continue,
171→            }
172→        };
173→        pieces.push(piece);
174→        index += 1;
175→    }
176→
177→    if pieces.is_empty() {
178→        return model_id.to_string();
179→    }
180→
181→    format!("Claude {}", pieces.join(" "))
182→}
