 663→            input_tokens: resp["usage"]["input_tokens"].as_u64().unwrap_or(0) as u32,
 664→            output_tokens: resp["usage"]["output_tokens"].as_u64().unwrap_or(0) as u32,
 665→            cache_read_tokens: resp["usage"]["cache_read_input_tokens"]
 666→                .as_u64()
 667→                .unwrap_or(0) as u32,
 668→            cache_write_tokens: resp["usage"]["cache_creation_input_tokens"]
 669→                .as_u64()
 670→                .unwrap_or(0) as u32,
 671→        };
 672→
 673→        if usage.cache_read_tokens > 0 || usage.cache_write_tokens > 0 {
 674→            debug!(
 675→                model = %self.model,
 676→                cache_read = usage.cache_read_tokens,
 677→                cache_write = usage.cache_write_tokens,
 678→                input = usage.input_tokens,
 679→                "anthropic prompt cache"
 680→            );
 681→        }
 682→
 683→        Ok(CompletionResponse {
 684→            text,
 685→            tool_calls,
 686→            usage,
 687→        })
 688→    }
