 702→    #[allow(clippy::collapsible_if)]
 703→    fn stream_with_tools(
 704→        &self,
 705→        messages: Vec<ChatMessage>,
 706→        tools: Vec<serde_json::Value>,
 707→    ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>> {
 708→        Box::pin(async_stream::stream! {
 709→            let caching = self.caching_enabled();
 710→            let (system_value, anthropic_messages) = to_anthropic_messages(&messages, caching);
 711→
 712→            let mut body = serde_json::json!({
 713→                "model": self.model,
 714→                "max_tokens": 4096,
 715→                "messages": anthropic_messages,
 716→                "stream": true,
 717→            });
 718→
 719→            if let Some(ref sys) = system_value {
 720→                body["system"] = sys.clone();
 721→            }
 722→
 723→            if !tools.is_empty() {
 724→                body["tools"] = serde_json::Value::Array(to_anthropic_tools(&tools));
 725→            }
 726→
 727→            self.apply_thinking(&mut body);
 728→
 729→            debug!(
 730→                model = %self.model,
 731→                messages_count = anthropic_messages.len(),
 732→                tools_count = tools.len(),
 733→                has_system = system_value.is_some(),
 734→                caching = caching,
 735→                reasoning_effort = ?self.reasoning_effort,
 736→                "anthropic stream_with_tools request"
 737→            );
 738→            trace!(body = %serde_json::to_string(&body).unwrap_or_default(), "anthropic stream request body");
 739→
 740→            let resp = match self
 741→                .client
 742→                .post(format!("{}/v1/messages", self.base_url))
 743→                .header("x-api-key", self.api_key.expose_secret())
 744→                .header("anthropic-version", "2023-06-01")
 745→                .header("content-type", "application/json")
 746→                .json(&body)
 747→                .send()
 748→                .await
 749→            {
 750→                Ok(r) => {
 751→                    if let Err(e) = r.error_for_status_ref() {
 752→                        let status = e.status().map(|s| s.as_u16()).unwrap_or(0);
 753→                        let retry_after_ms = retry_after_ms_from_headers(r.headers());
 754→                        let body_text = r.text().await.unwrap_or_default();
 755→                        yield StreamEvent::Error(with_retry_after_marker(
 756→                            format!("HTTP {status}: {body_text}"),
 757→                            retry_after_ms,
 758→                        ));
 759→                        return;
 760→                    }
 761→                    r
 762→                }
 763→                Err(e) => {
 764→                    yield StreamEvent::Error(e.to_string());
 765→                    return;
 766→                }
 767→            };
 768→
 769→            let mut byte_stream = resp.bytes_stream();
 770→            let mut buf = String::new();
 771→            let mut input_tokens: u32 = 0;
 772→            let mut output_tokens: u32 = 0;
 773→            let mut cache_read_tokens: u32 = 0;
 774→            let mut cache_write_tokens: u32 = 0;
 775→
 776→            // Track current content block index for tool calls.
 777→            let mut current_block_index: Option<usize> = None;
 778→
 779→            while let Some(chunk) = byte_stream.next().await {
 780→                let chunk = match chunk {
 781→                    Ok(c) => c,
 782→                    Err(e) => {
 783→                        yield StreamEvent::Error(e.to_string());
 784→                        return;
 785→                    }
 786→                };
 787→                buf.push_str(&String::from_utf8_lossy(&chunk));
 788→
 789→                while let Some(pos) = buf.find("\n\n") {
 790→                    let block = buf[..pos].to_string();
 791→                    buf = buf[pos + 2..].to_string();
 792→
 793→                    for line in block.lines() {
 794→                        if let Some(data) = line.strip_prefix("data: ") {
 795→                            if let Ok(evt) = serde_json::from_str::<serde_json::Value>(data) {
 796→                                let evt_type = evt["type"].as_str().unwrap_or("");
 797→                                match evt_type {
 798→                                    "content_block_start" => {
 799→                                        let index = evt["index"].as_u64().unwrap_or(0) as usize;
 800→                                        let content_block = &evt["content_block"];
 801→                                        let block_type = content_block["type"].as_str().unwrap_or("");
 802→
 803→                                        if block_type == "tool_use" {
 804→                                            let id = content_block["id"].as_str().unwrap_or("").to_string();
 805→                                            let name = content_block["name"].as_str().unwrap_or("").to_string();
 806→                                            current_block_index = Some(index);
 807→                                            yield StreamEvent::ToolCallStart { id, name, index };
 808→                                        }
 809→                                    }
 810→                                    "content_block_delta" => {
 811→                                        let delta = &evt["delta"];
 812→                                        let delta_type = delta["type"].as_str().unwrap_or("");
 813→
 814→                                        if delta_type == "text_delta" {
 815→                                            if let Some(text) = delta["text"].as_str() {
 816→                                                if !text.is_empty() {
 817→                                                    yield StreamEvent::Delta(text.to_string());
 818→                                                }
 819→                                            }
 820→                                        } else if delta_type == "input_json_delta" {
 821→                                            if let Some(partial_json) = delta["partial_json"].as_str() {
 822→                                                let index = evt["index"].as_u64().unwrap_or(0) as usize;
 823→                                                yield StreamEvent::ToolCallArgumentsDelta {
 824→                                                    index,
 825→                                                    delta: partial_json.to_string(),
 826→                                                };
 827→                                            }
 828→                                        }
 829→                                    }
 830→                                    "content_block_stop" => {
 831→                                        let index = evt["index"].as_u64().unwrap_or(0) as usize;
 832→                                        // Only emit ToolCallComplete if this was a tool_use block.
 833→                                        if current_block_index == Some(index) {
 834→                                            yield StreamEvent::ToolCallComplete { index };
 835→                                            current_block_index = None;
 836→                                        }
 837→                                    }
 838→                                    "message_delta" => {
 839→                                        let u = &evt["usage"];
 840→                                        if let Some(v) = u["output_tokens"].as_u64() {
 841→                                            output_tokens = v as u32;
 842→                                        }
 843→                                        // Anthropic may report cache tokens in delta
 844→                                        if let Some(v) = u["cache_read_input_tokens"].as_u64() {
 845→                                            cache_read_tokens = v as u32;
 846→                                        }
 847→                                        if let Some(v) = u["cache_creation_input_tokens"].as_u64() {
 848→                                            cache_write_tokens = v as u32;
 849→                                        }
 850→                                    }
 851→                                    "message_start" => {
 852→                                        let u = &evt["message"]["usage"];
 853→                                        if let Some(v) = u["input_tokens"].as_u64() {
 854→                                            input_tokens = v as u32;
 855→                                        }
 856→                                        if let Some(v) = u["cache_read_input_tokens"].as_u64() {
 857→                                            cache_read_tokens = v as u32;
 858→                                        }
 859→                                        if let Some(v) = u["cache_creation_input_tokens"].as_u64() {
 860→                                            cache_write_tokens = v as u32;
 861→                                        }
 862→                                    }
 863→                                    "message_stop" => {
 864→                                        yield StreamEvent::Done(Usage {
 865→                                            input_tokens,
 866→                                            output_tokens,
 867→                                            cache_read_tokens,
 868→                                            cache_write_tokens,
 869→                                        });
 870→                                        return;
 871→                                    }
 872→                                    "error" => {
 873→                                        let msg = evt["error"]["message"]
 874→                                            .as_str()
 875→                                            .unwrap_or("unknown error");
 876→                                        yield StreamEvent::Error(msg.to_string());
 877→                                        return;
 878→                                    }
 879→                                    _ => {}
 880→                                }
 881→                            }
 882→                        }
 883→                    }
 884→                }
 885→            }
 886→        })
 887→    }
 888→}
