 36→    /// Register models from a [`RediscoveryResult`], skipping those already
 37→    /// present. All I/O (model list fetches, Ollama probes) must be completed
 38→    /// before calling this — it only does fast in-memory work.
 39→    ///
 40→    /// Returns the number of newly registered models.
 41→    pub fn register_rediscovered_models(
 42→        &mut self,
 43→        config: &ProvidersConfig,
 44→        env_overrides: &HashMap<String, String>,
 45→        result: &RediscoveryResult,
 46→    ) -> usize {
 47→        let fetched = &result.models;
 48→        let mut added = 0usize;
 49→
 50→        // ── Anthropic builtin ─────────────────────────────────────────
 51→        if fetched.contains_key("anthropic")
 52→            && config.is_enabled("anthropic")
 53→            && let Some(key) =
 54→                resolve_api_key(config, "anthropic", "ANTHROPIC_API_KEY", env_overrides)
 55→        {
 56→            let base_url = config
 57→                .get("anthropic")
 58→                .and_then(|e| e.base_url.clone())
 59→                .or_else(|| env_value(env_overrides, "ANTHROPIC_BASE_URL"))
 60→                .unwrap_or_else(|| "https://api.anthropic.com".into());
 61→            let alias = config.get("anthropic").and_then(|e| e.alias.clone());
 62→            let provider_label = alias.clone().unwrap_or_else(|| "anthropic".into());
 63→            let cache_retention = config
 64→                .get("anthropic")
 65→                .map(|e| e.cache_retention)
 66→                .unwrap_or(moltis_config::CacheRetention::Short);
 67→            let models = Self::desired_anthropic_models(config, fetched);
 68→
 69→            added += self.replace_anthropic_catalog(
 70→                models,
 71→                &key,
 72→                &base_url,
 73→                &provider_label,
 74→                alias,
 75→                cache_retention,
 76→            );
 77→        }
 78→
 79→        // ── OpenAI builtin ────────────────────────────────────────────
 80→        if let Some(models) = fetched.get("openai")
 81→            && config.is_enabled("openai")
 82→            && let Some(key) = resolve_api_key(config, "openai", "OPENAI_API_KEY", env_overrides)
 83→        {
 84→            let base_url = config
 85→                .get("openai")
 86→                .and_then(|e| e.base_url.clone())
 87→                .or_else(|| env_value(env_overrides, "OPENAI_BASE_URL"))
 88→                .unwrap_or_else(|| "https://api.openai.com/v1".into());
 89→            let alias = config.get("openai").and_then(|e| e.alias.clone());
 90→            let provider_label = alias.unwrap_or_else(|| "openai".into());
 91→            let stream_transport = config
 92→                .get("openai")
 93→                .map(|entry| entry.stream_transport)
 94→                .unwrap_or(ProviderStreamTransport::Sse);
 95→
 96→            for model in models {
 97→                if self.has_provider_model(&provider_label, &model.id) {
 98→                    continue;
 99→                }
100→                let provider = Arc::new(
101→                    openai::OpenAiProvider::new_with_name(
102→                        key.clone(),
103→                        model.id.clone(),
104→                        base_url.clone(),
105→                        provider_label.clone(),
106→                    )
107→                    .with_stream_transport(stream_transport),
108→                );
109→                self.register(
110→                    ModelInfo {
111→                        id: model.id.clone(),
112→                        provider: provider_label.clone(),
113→                        display_name: model.display_name.clone(),
114→                        created_at: model.created_at,
115→                        recommended: model.recommended,
116→                        capabilities: model
117→                            .capabilities
118→                            .unwrap_or_else(|| ModelCapabilities::infer(&model.id)),
119→                    },
120→                    provider,
121→                );
122→                added += 1;
123→            }
124→        }
125→
126→        // ── OpenAI-compatible providers ───────────────────────────────
127→        for def in OPENAI_COMPAT_PROVIDERS {
128→            let Some(models) = fetched.get(def.config_name) else {
129→                continue;
130→            };
131→            if !config.is_enabled(def.config_name) {
132→                continue;
133→            }
134→
135→            let key = resolve_api_key(config, def.config_name, def.env_key, env_overrides);
136→            let key = if !def.requires_api_key {
137→                key.or_else(|| Some(secrecy::Secret::new(def.config_name.into())))
138→            } else if def.config_name == "gemini" {
139→                key.or_else(|| env_value(env_overrides, "GOOGLE_API_KEY").map(secrecy::Secret::new))
140→            } else {
141→                key
142→            };
143→            let Some(key) = key else {
144→                continue;
145→            };
146→
147→            let base_url = config
148→                .get(def.config_name)
149→                .and_then(|e| e.base_url.clone())
150→                .or_else(|| env_value(env_overrides, def.env_base_url_key))
151→                .unwrap_or_else(|| def.default_base_url.into());
152→            let alias = config.get(def.config_name).and_then(|e| e.alias.clone());
153→            let provider_label = alias.unwrap_or_else(|| def.config_name.into());
154→            let stream_transport = config
155→                .get(def.config_name)
156→                .map(|entry| entry.stream_transport)
157→                .unwrap_or(ProviderStreamTransport::Sse);
158→            let cache_retention = config
159→                .get(def.config_name)
160→                .map(|e| e.cache_retention)
161→                .unwrap_or(moltis_config::CacheRetention::Short);
162→            let config_tool_mode = config
163→                .get(def.config_name)
164→                .map(|e| e.tool_mode)
165→                .unwrap_or_default();
166→            let is_ollama = def.config_name == "ollama";
167→
168→            // Use pre-fetched Ollama `/api/show` probes (already collected
169→            // outside the registry lock by `fetch_discoverable_models`).
170→            let empty_probes = HashMap::new();
171→            let ollama_probes: &HashMap<String, OllamaShowResponse> = if is_ollama {
172→                &result.ollama_probes
173→            } else {
174→                &empty_probes
175→            };
176→
177→            for model in models {
178→                if self.has_provider_model(&provider_label, &model.id) {
179→                    continue;
180→                }
181→                let effective_tool_mode = if is_ollama {
182→                    resolve_ollama_tool_mode(
183→                        config_tool_mode,
184→                        &model.id,
185→                        ollama_probes.get(&model.id),
186→                    )
187→                } else if !matches!(config_tool_mode, moltis_config::ToolMode::Auto) {
188→                    config_tool_mode
189→                } else {
190→                    moltis_config::ToolMode::Auto
191→                };
192→
193→                let mut oai = openai::OpenAiProvider::new_with_name(
194→                    key.clone(),
195→                    model.id.clone(),
196→                    base_url.clone(),
197→                    provider_label.clone(),
198→                )
199→                .with_stream_transport(stream_transport)
200→                .with_cache_retention(cache_retention);
201→
202→                if !matches!(effective_tool_mode, moltis_config::ToolMode::Auto) {
203→                    oai = oai.with_tool_mode(effective_tool_mode);
204→                }
205→                if let Some(strict) = config.get(def.config_name).and_then(|e| e.strict_tools) {
206→                    oai = oai.with_strict_tools(strict);
207→                }
208→
209→                self.register(
210→                    ModelInfo {
211→                        id: model.id.clone(),
212→                        provider: provider_label.clone(),
213→                        display_name: model.display_name.clone(),
214→                        created_at: model.created_at,
215→                        recommended: model.recommended,
216→                        capabilities: model
217→                            .capabilities
218→                            .unwrap_or_else(|| ModelCapabilities::infer(&model.id)),
219→                    },
220→                    Arc::new(oai),
221→                );
222→                added += 1;
223→            }
224→        }
225→
226→        // ── Custom providers ──────────────────────────────────────────
227→        for (name, entry) in &config.providers {
228→            if !name.starts_with("custom-") || !entry.enabled {
229→                continue;
230→            }
231→            let Some(models) = fetched.get(name.as_str()) else {
232→                continue;
233→            };
234→            let Some(api_key) = entry
235→                .api_key
236→                .as_ref()
