239→                continue;
240→            };
241→            let Some(base_url) = entry.base_url.as_ref().filter(|u| !u.trim().is_empty()) else {
242→                continue;
243→            };
244→            let custom_tool_mode = entry.tool_mode;
245→
246→            for model in models {
