1022→    pub fn get(&self, model_id: &str) -> Option<Arc<dyn LlmProvider>> {
1023→        let (base_id, reasoning) = split_reasoning_suffix(model_id);
1024→        let provider = self
1025→            .resolve_registry_model_id(base_id, None)
1026→            .as_deref()
1027→            .and_then(|id| self.providers.get(id))
1028→            .cloned()?;
1029→        if let Some(effort) = reasoning {
1030→            let new_provider = Arc::clone(&provider).with_reasoning_effort(effort);
1031→            if new_provider.is_none() {
1032→                tracing::warn!(
1033→                    model_id,
1034→                    ?effort,
1035→                    "provider does not support reasoning effort; ignoring suffix"
1036→                );
1037→            }
1038→            Some(new_provider.unwrap_or(provider))
1039→        } else {
1040→            Some(provider)
1041→        }
1042→    }
