1071→    /// Return the base model list plus reasoning-effort variants for supported models.
1072→    ///
1073→    /// For each model that supports extended thinking, three additional entries
1074→    /// are appended: `<id>@reasoning-low`, `<id>@reasoning-medium`, `<id>@reasoning-high`.
1075→    /// These virtual IDs are resolved by `get()` back to the base provider with
1076→    /// the corresponding reasoning effort applied.
1077→    #[must_use]
1078→    pub fn list_models_with_reasoning_variants(&self) -> Vec<ModelInfo> {
1079→        let mut result = Vec::with_capacity(self.models.len() * 4);
1080→        for m in &self.models {
1081→            result.push(m.clone());
1082→            if m.capabilities.reasoning {
1083→                for &(suffix, _) in REASONING_SUFFIXES {
1084→                    let label = suffix.strip_prefix("reasoning-").unwrap_or(suffix);
1085→                    result.push(ModelInfo {
1086→                        id: format!("{}{REASONING_SUFFIX_SEP}{suffix}", m.id),
1087→                        provider: m.provider.clone(),
1088→                        display_name: format!("{} ({label} reasoning)", m.display_name),
1089→                        created_at: m.created_at,
1090→                        recommended: false,
1091→                        capabilities: ModelCapabilities {
1092→                            reasoning: true,
1093→                            ..m.capabilities
1094→                        },
1095→                    });
1096→                }
1097→            }
1098→        }
1099→        result
1100→    }
