1123→    /// Return fallback providers ordered by affinity to the given primary:
1124→    ///
1125→    /// 1. Same model ID on a different provider backend (e.g. `gpt-4o` via openrouter)
1126→    /// 2. Subscription providers (`openai-codex`, `github-copilot`)
1127→    /// 3. Other models from the same provider (e.g. `claude-opus-4` when primary is `claude-sonnet-4`)
1128→    /// 4. Models from other providers
1129→    ///
1130→    /// The primary itself is excluded from the result.
1131→    pub fn fallback_providers_for(
1132→        &self,
1133→        primary_model_id: &str,
1134→        primary_provider_name: &str,
1135→    ) -> Vec<Arc<dyn LlmProvider>> {
1136→        let primary_raw_model_id = raw_model_id(primary_model_id);
1137→        let mut ranked: Vec<(u8, usize, usize, Arc<dyn LlmProvider>)> = Vec::new();
1138→
1139→        for (idx, info) in self.models.iter().enumerate() {
1140→            if info.id == primary_model_id && info.provider == primary_provider_name {
1141→                continue; // skip the primary itself
1142→            }
1143→            let Some(p) = self.providers.get(&info.id).cloned() else {
1144→                continue;
1145→            };
1146→            let provider_rank = subscription_preference_rank(&info.provider);
1147→            let bucket = if raw_model_id(&info.id) == primary_raw_model_id {
1148→                0
1149→            } else if provider_rank == 0 {
1150→                1
1151→            } else if info.provider == primary_provider_name {
1152→                2
1153→            } else {
1154→                3
1155→            };
1156→            ranked.push((bucket, provider_rank, idx, p));
1157→        }
1158→
1159→        ranked.sort_by_key(|(bucket, provider_rank, idx, _)| (*bucket, *provider_rank, *idx));
