139→/// Asynchronously fetch models from all discoverable provider APIs.
140→///
141→/// Runs `/v1/models` (or Ollama `/api/tags`) for each eligible provider
142→/// concurrently, then batch-probes any discovered Ollama models via
143→/// `/api/show` for tool-mode metadata. Returns everything needed for
144→/// lock-free registration.
145→///
146→/// `provider_filter` narrows the scope to a single provider name (case-
147→/// insensitive comparison against config name or alias).
148→pub async fn fetch_discoverable_models(
149→    config: &ProvidersConfig,
150→    env_overrides: &HashMap<String, String>,
151→    provider_filter: Option<&str>,
152→) -> RediscoveryResult {
153→    use futures::future::join_all;
154→
155→    let filter_matches =
156→        |name: &str| -> bool { provider_filter.is_none_or(|f| f.eq_ignore_ascii_case(name)) };
157→
158→    let mut tasks: Vec<(
159→        String,
160→        Pin<Box<dyn Future<Output = anyhow::Result<Vec<DiscoveredModel>>> + Send>>,
161→    )> = Vec::new();
162→
163→    // ── OpenAI builtin ────────────────────────────────────────────────
164→    if filter_matches("openai")
165→        && config.is_enabled("openai")
166→        && !cfg!(test)
167→        && let Some(key) = resolve_api_key(config, "openai", "OPENAI_API_KEY", env_overrides)
168→        && should_fetch_models(config, "openai")
169→    {
170→        let base_url = config
171→            .get("openai")
172→            .and_then(|e| e.base_url.clone())
173→            .or_else(|| env_value(env_overrides, "OPENAI_BASE_URL"))
174→            .unwrap_or_else(|| "https://api.openai.com/v1".into());
175→        tasks.push((
176→            "openai".into(),
177→            Box::pin(openai::fetch_models_from_api(key, base_url)),
178→        ));
179→    }
180→
181→    // ── Anthropic builtin ─────────────────────────────────────────────
182→    if filter_matches("anthropic")
183→        && config.is_enabled("anthropic")
184→        && !cfg!(test)
185→        && let Some(key) = resolve_api_key(config, "anthropic", "ANTHROPIC_API_KEY", env_overrides)
186→        && should_fetch_models(config, "anthropic")
187→    {
188→        let base_url = config
189→            .get("anthropic")
190→            .and_then(|e| e.base_url.clone())
191→            .or_else(|| env_value(env_overrides, "ANTHROPIC_BASE_URL"))
192→            .unwrap_or_else(|| "https://api.anthropic.com".into());
193→        tasks.push((
194→            "anthropic".into(),
195→            Box::pin(anthropic::fetch_models_from_api(key, base_url)),
196→        ));
197→    }
198→
199→    // ── OpenAI-compatible providers ───────────────────────────────────
200→    for def in OPENAI_COMPAT_PROVIDERS {

