 12→/// Return the context window size for a model ID, respecting config overrides.
 13→///
 14→/// Precedence (highest to lowest):
 15→/// 1. Provider-scoped config override (`provider_overrides[model_id].context_window`)
 16→/// 2. Global config override (`global_overrides[model_id].context_window`)
 17→/// 3. Hardcoded heuristic ([`context_window_for_model_inner`])
 18→///
 19→/// Both override maps use the **normalized** model ID (after
 20→/// [`capability_model_id`] processing) as the lookup key.
 21→///
 22→/// Note: This function accepts `HashMap<String, u32>` (not the config crate's
 23→/// `ModelOverride`) to keep the providers crate independent of the config crate.
 24→/// Callers are responsible for extracting the `u32` from `ModelOverride.context_window`.
 25→///
 26→/// When no config is provided, this is equivalent to [`context_window_for_model`].
 27→#[must_use]
 28→pub fn context_window_for_model_with_config(
 29→    model_id: &str,
 30→    global_overrides: &std::collections::HashMap<String, u32>,
 31→    provider_overrides: &std::collections::HashMap<String, u32>,
 32→) -> u32 {
 33→    let normalized = capability_model_id(model_id);
 34→
 35→    // 1. Provider-scoped override (highest precedence)
 36→    if let Some(&cw) = provider_overrides.get(normalized) {
 37→        return cw;
 38→    }
 39→    // 2. Global override
 40→    if let Some(&cw) = global_overrides.get(normalized) {
 41→        return cw;
 42→    }
 43→    // 3. Hardcoded heuristic
 44→    context_window_for_model_inner(model_id)
 45→}
 46→
 47→/// Inner heuristic — kept private so callers go through the public wrappers.
 48→fn context_window_for_model_inner(model_id: &str) -> u32 {
 49→    let model_id = capability_model_id(model_id);
 50→    // Codestral has the largest window at 256k.
 51→    if model_id.starts_with("codestral") {
 52→        return 256_000;
 53→    }
 54→    // Claude models: 200k.
 55→    if model_id.starts_with("claude-") {
 56→        return 200_000;
 57→    }
 58→    // OpenAI o3/o4-mini: 200k.
 59→    if model_id.starts_with("o3") || model_id.starts_with("o4-mini") {
 60→        return 200_000;
 61→    }
 62→    // GPT-4o, GPT-4-turbo, GPT-5 series: 128k.
 63→    if model_id.starts_with("gpt-4") || model_id.starts_with("gpt-5") {
 64→        return 128_000;
 65→    }
 66→    // Mistral Large: 128k.
 67→    if model_id.starts_with("mistral-large") {
 68→        return 128_000;
 69→    }
 70→    // Gemini: 1M context.
 71→    if model_id.starts_with("gemini-") {
 72→        return 1_000_000;
 73→    }
 74→    // Kimi K2.5: 128k.
 75→    if model_id.starts_with("kimi-") {
 76→        return 128_000;
 77→    }
 78→    // MiniMax M2/M2.1/M2.5/M2.7: 204,800.
 79→    if model_id.starts_with("MiniMax-") {
 80→        return 204_800;
 81→    }
 82→    // Z.AI GLM-4-32B: 128k.
 83→    if model_id == "glm-4-32b-0414-128k" {
 84→        return 128_000;
 85→    }
 86→    // Z.AI GLM-5/4.7/4.6/4.5 series: 128k.
 87→    if model_id.starts_with("glm-") {
 88→        return 128_000;
 89→    }
 90→    // Qwen3 series (Qwen3, Qwen3-Coder): 128k.
 91→    if model_id.starts_with("qwen3") {
 92→        return 128_000;
 93→    }
 94→    // Default fallback.
 95→    200_000
 96→}
 97→
 98→/// Returns `false` for model IDs that are clearly not chat-completion models
 99→/// (image generators, TTS, speech-to-text, embeddings, moderation, etc.).
100→///
101→/// Provider APIs like OpenAI's `/v1/models` return every model in the account.
102→/// Since no capability metadata is exposed we filter by well-known prefixes and
103→/// patterns. This is applied both at discovery time and at display time so that
104→/// non-chat models never appear in the UI.
105→pub fn is_chat_capable_model(model_id: &str) -> bool {
106→    let id = capability_model_id(model_id);
107→    const NON_CHAT_PREFIXES: &[&str] = &[
108→        "dall-e",
109→        "gpt-image",
110→        "chatgpt-image",
111→        "gpt-audio",
112→        "tts-",
113→        "whisper",
114→        "text-embedding",
115→        "claude-embedding",
116→        "claude-embeddings",
117→        "omni-moderation",
118→        "moderation-",
119→        "sora",
120→        // Google Gemini non-chat models
121→        "imagen-",
122→        "gemini-embedding",
123→        "learnlm-",
124→        "gemma-3n-",
125→        // Z.AI non-chat models
126→        "glm-image",
127→        "glm-asr",
128→        "glm-ocr",
129→        "cogvideo",
130→        "cogview",
131→        "vidu",
132→        "autoglm-phone",
133→    ];
134→    for prefix in NON_CHAT_PREFIXES {
135→        if id.starts_with(prefix) {
136→            return false;
137→        }
138→    }
139→    // TTS / audio-only / realtime / transcription variants
140→    if id.contains("-tts") || id.contains("-audio-") || id.ends_with("-audio") {
141→        return false;
142→    }
143→    if id.contains("-realtime-") || id.ends_with("-realtime") {
144→        return false;
145→    }
146→    if id.contains("-transcribe") {
147→        return false;
148→    }
149→    // Gemini live (real-time dialogue) and image-generation variants
150→    if id.contains("-live-") || id.contains("-image-") {
151→        return false;
152→    }
153→    true
154→}
155→
156→/// Check if a model supports tool/function calling.
157→///
158→/// Most modern chat models support tools, but legacy completions-only models
159→/// (e.g. `babbage-002`, `davinci-002`) and non-chat models do not.
160→/// This is checked per-model rather than per-provider so that providers
161→/// exposing mixed catalogs report accurate tool support.
162→pub fn supports_tools_for_model(model_id: &str) -> bool {
163→    let id = capability_model_id(model_id);
164→    // Legacy completions-only models — no tool support
165→    if id.starts_with("babbage") || id.starts_with("davinci") {
166→        return false;
167→    }
168→    // Non-chat model families — never support tools
169→    if id.starts_with("dall-e")
170→        || id.starts_with("gpt-image")
171→        || id.starts_with("tts-")
172→        || id.starts_with("whisper")
173→        || id.starts_with("text-embedding")
174→        || id.starts_with("claude-embedding")
175→        || id.starts_with("claude-embeddings")
176→        || id.starts_with("omni-moderation")
177→    {
178→        return false;
179→    }
180→    // Default: assume tool support for modern chat models
181→    true
182→}
183→
184→/// Check if a model supports vision (image inputs).
185→///
186→/// Vision-capable models can process images in tool results and user messages.
187→/// When true, the runner sends images as multimodal content blocks rather than
188→/// stripping them from the context.
189→///
190→/// Uses a deny-list approach: most modern LLMs support vision, so unknown
191→/// models default to `true`. The consequence of a false positive (sending
192→/// images to a text-only model) is an API error — visible and diagnosable.
193→/// The consequence of a false negative (stripping images from a capable model)
194→/// is a silent failure that confuses users.
195→pub fn supports_vision_for_model(model_id: &str) -> bool {
196→    let id = capability_model_id(model_id);
197→
198→    // ── Known text-only models ──────────────────────────────────────
199→    // Code-focused models
200→    if id.starts_with("codestral") {
201→        return false;
202→    }
203→    // Legacy OpenAI models without vision
204→    if id.starts_with("gpt-3.5") || id.starts_with("text-") || id.starts_with("gpt-4-") {
205→        // gpt-4-turbo and gpt-4-vision variants support vision
206→        if id.starts_with("gpt-4-turbo") || id.starts_with("gpt-4-vision") {
207→            return true;
208→        }
209→        return false;
210→    }
211→    // Z.AI GLM text-only models (vision variants contain 'v' suffix)
212→    if id.starts_with("glm-") && !id.contains('v') {
213→        return false;
214→    }
215→
216→    // ── Default: assume vision support ──────────────────────────────
217→    true
218→}
219→
220→/// Check if a model supports reasoning/extended thinking.
221→///
222→/// Reasoning-capable models can use the `reasoning_effort` configuration
223→/// to control the depth of extended thinking. This is used by the UI and
224→/// validation to inform users when reasoning_effort is set on a model
225→/// that doesn't support it.
226→pub fn supports_reasoning_for_model(model_id: &str) -> bool {
227→    let id = capability_model_id(model_id);
228→    // Anthropic Claude Opus 4.5+ and Sonnet 4.5+
229→    if id.starts_with("claude-opus-4-5")
230→        || id.starts_with("claude-sonnet-4-5")
231→        || id.starts_with("claude-opus-4-6")
232→        || id.starts_with("claude-sonnet-4-6")
233→    {
234→        return true;
235→    }
236→    // Claude 3.7 Sonnet supports extended thinking
237→    if id.starts_with("claude-3-7-sonnet") {
238→        return true;
239→    }
240→    // OpenAI o-series reasoning models
241→    if id.starts_with("o1") || id.starts_with("o3") || id.starts_with("o4") {
242→        return true;
243→    }
244→    // Gemini 2.5+ with thinking (2.5 Flash/Pro, 3 Flash, 3.1 Pro)
245→    if id.starts_with("gemini-2.5") || id.starts_with("gemini-3") {
246→        return true;
247→    }
248→    // OpenAI GPT-5.x models support reasoning_effort
249→    if id.starts_with("gpt-5") {
250→        return true;
251→    }
252→    // DeepSeek R1 / reasoning models
253→    if id.contains("deepseek-r1") || id.contains("deepseek-reasoner") {
254→        return true;
255→    }
256→    false
257→}
