274→impl ModelCapabilities {
275→    /// Infer capabilities from the model ID using the pattern-matching heuristics.
276→    #[must_use]
277→    pub fn infer(model_id: &str) -> Self {
278→        Self {
279→            tools: supports_tools_for_model(model_id),
280→            vision: supports_vision_for_model(model_id),
281→            reasoning: supports_reasoning_for_model(model_id),
282→        }
283→    }
284→}
